INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0401319F$$, 2027, $$The VC-25B Program, formerly known as the Presidential Aircraft Recapitalization (PAR) Program, replaces the Presidential VC-25A fleet which faces capability gaps,
rising maintenance costs, and parts obsolescence as it ages beyond 30 years. The VC-25B Program delivers two new aircraft to meet the requirements for the President
to execute the duties of Head of State, Chief Executive, and Commander-in-Chief. The VC-25B Program uniquely modifies two Boeing 747-8 commercial aircraft to
provide the President, staff, and guests with safe and reliable air transportation with the equivalent level of communications capability and security available in the White
House. The modifications to the 747-8 aircraft include an electrical power upgrade with dual Auxiliary Power Units that are usable in flight, a mission communication
system, a work and rest environment, an executive interior, military avionics, a self-defense system, independent enplaning and deplaning, and independent baggage
loading. No significant changes to the existing VC-25A Concept of Operations or Concept of Employment are expected. This budget provides for Post-Milestone B (MS
B) design, integration, modification, product support and test of two aircraft to make them Presidential mission ready.

Funds may be used to lease VC-25B test equipment, as well as address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS)
issues.

This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs
funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, and 0605898F.

This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and
manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$The VC-25B Program, formerly known as the Presidential Aircraft Recapitalization (PAR) Program, replaces the Presidential VC-25A fleet which faces capability gaps,
rising maintenance costs, and parts obsolescence as it ages beyond 30 years. The VC-25B Program delivers two new aircraft to meet the requirements for the President
to execute the duties of Head of State, Chief Executive, and Commander-in-Chief. The VC-25B Program uniquely modifies two Boeing 747-8 commercial aircraft to
provide the President, staff, and guests with safe and reliable air transportation with the equivalent level of communications capability and security available in the White
House. The modifications to the 747-8 aircraft include an electrical power upgrade with dual Auxiliary Power Units that are usable in flight, a mission communication
system, a work and rest environment, an executive interior, military avionics, a self-defense system, independent enplaning and deplaning, and independent baggage
loading. No significant changes to the existing VC-25A Concept of Operations or Concept of Employment are expected. This budget provides for Post-Milestone B (MS
B) design, integration, modification, product support and test of two aircraft to make them Presidential mission ready.

Funds may be used to lease VC-25B test equipment, as well as address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS)
issues.

This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs
funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, and 0605898F.

This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and
manufacturing development tasks aimed at meeting validated requirements prior to full rate production.

